mapper.select:
SELECT *
FROM system_monitor
WHERE service_name = #{serviceName}
ORDER BY report_time DESC, id DESC
LIMIT #{limitSize}

SELECT *
FROM system_monitor


        AND status = #{status}


        AND cpu_usage  >=  #{minCpuUsage}


        AND memory_usage  >=  #{minMemoryUsage}


        AND request_count > 0
        AND (error_count / request_count)  >=  #{minErrorRate}


        AND (
            status != 'UP'
            OR cpu_usage  >=  80
            OR memory_usage  >=  80
        )


ORDER BY report_time DESC, id DESC
